        tasks: ["Download MySQL Community Edition from dev.mysql.com/downloads", "Install with Developer Default setup type (Server + Workbench + Shell)", "Set a strong root password during installation", "Run mysql_secure_installation to remove anonymous users and test database", "Connect as root: mysql -u root -p and verify with SELECT VERSION();", "Create a dedicated lab user with restricted privileges", "Grant SELECT, INSERT, UPDATE on dbms_lab.* to the lab user", "Test the new user by connecting and running SHOW DATABASES;", "Create a read-only user with only SELECT privileges", "Inspect configuration: SHOW VARIABLES LIKE 'character_set_server';"],
        viva: [{ q: "What does mysql_secure_installation do?", a: "It sets the root password, removes anonymous users, disables remote root login, drops the test database, and reloads privilege tables." }, { q: "What is the principle of least privilege?", a: "Users should only be granted the minimum permissions needed for their tasks — never global ALL PRIVILEGES unless absolutely necessary." }, { q: "What is UTF8MB4 and why use it instead of UTF8?", a: "UTF8MB4 supports the full Unicode character set including 4-byte characters (emoji, rare CJK characters). Old UTF8 in MySQL only supports 3-byte characters and misses emojis." }, { q: "What does FLUSH PRIVILEGES do?", a: "It reloads the grant tables from the mysql database, applying any permission changes immediately without restarting the server." }]
