        tasks: ["Create Department table with PRIMARY KEY, NOT NULL, UNIQUE, CHECK, DEFAULT constraints", "Create Employee table with FOREIGN KEY referencing Department with ON DELETE CASCADE", "Insert 5 departments and 15 employees using multi-row INSERT statements", "Test CHECK constraint violation: insert Salary < 15000 — observe ERROR 3819", "Test NOT NULL violation: insert without EmpName — observe ERROR 1364", "Test UNIQUE violation: duplicate Email — observe ERROR 1062", "Test FOREIGN KEY violation: invalid DeptID — observe ERROR 1452", "Demonstrate ON DELETE CASCADE: delete a department and verify child employees are auto-deleted", "Practice ALTER TABLE: ADD COLUMN, MODIFY COLUMN, RENAME COLUMN, ADD CONSTRAINT, DROP COLUMN", "Compare DELETE (targeted, rollback-able) vs TRUNCATE (all rows, resets AUTO_INCREMENT) vs DROP (destroys table)"],
        viva: [{ q: "What is the difference between DELETE, TRUNCATE, and DROP?", a: "DELETE removes specific rows via WHERE, can be rolled back, fires triggers, doesn't reset AUTO_INCREMENT. TRUNCATE removes ALL rows instantly, cannot be rolled back, resets AUTO_INCREMENT. DROP destroys the entire table structure and all data permanently." }, { q: "What does ON DELETE CASCADE do?", a: "When a parent row is deleted, all child rows referencing it via FOREIGN KEY are automatically deleted too." }, { q: "Can a UNIQUE column contain NULL?", a: "Yes. In MySQL, a UNIQUE column can contain multiple NULL values because NULL is not equal to NULL (NULL != NULL in SQL)." }, { q: "What is the difference between PRIMARY KEY and UNIQUE?", a: "A table can have only one PRIMARY KEY and it cannot contain NULL. A table can have multiple UNIQUE constraints and UNIQUE columns can contain NULL." }]
